solutions.javascript:
// Solution
function insert(trie, word) {
  if (word in trie) {
    trie[word].duplicate = true;
  } else {
    for (var i = 0; i < word.length; i++) {
      if (!(word[i] in trie)) {
        trie[word[i]] = {};
      }
      trie = trie[word[i]];
    }
  }
  return trie;
}

// Example usage
var trie = {};
trie = insert(trie, 'apple');
trie = insert(trie, 'app');
console.log(trie);
